# Read and parse the current file to merge custom entries, preserving data
try:
    with open('src/main/resources/core_knowledge.json') as f:
        data = json.load(f)
    print(f"Loaded {len(data)} entries from existing file")
    
    # Merge entries preserving existing file content securely
    existing_tasks = {e['task'].strip() for e in entries}
    merged_count = 0
    for item in data:
        if item.get('task') and item['task'].strip() not in existing_tasks:
            entries.append(item)
            merged_count += 1
    if merged_count > 0:
        print(f"Successfully merged {merged_count} unique entries from existing JSON into our memory.")
except Exception as e:
    print(f"Could not load/merge existing core_knowledge.json, starting fresh with core registry. Info: {e}")

print("Writing file...")
with open('src/main/resources/core_knowledge.json', 'w', encoding='utf-8') as f:
    json.dump(entries, f, indent=2, ensure_ascii=False)

